const { createDeprecationLogger } = require('@meli/deprecation');

const logger = createDeprecationLogger('frontend-statsd', {
  once: true,
});

// Create a proxy to wrap the statsd client on non-production to reduce performance impact
const deprecationWrapper = (statsd) =>
  process.env.NODE_ENV === 'production'
    ? statsd
    : new Proxy(statsd, {
        get(target, prop) {
          const value = target[prop];

          logger(
            'This module is deprecated. Please use the new `@meli/statsd` package instead. Docs: https://nordic.adminml.com/docs/migration-guides/modules/statsd/migrate-to-meli-statsd',
          );

          return typeof value === 'function' ? value.bind(target) : value;
        },
      });

module.exports = {
  deprecationWrapper,
};
